import React from 'react';
import './Work.css';

const PROJECTS = [
  { title: 'Monochrome Momentum', category: 'Brand Film', year: '2026' },
  { title: 'Velocity of Silence', category: 'Music Video', year: '2025' },
  { title: 'Noisy City, Quiet Frame', category: 'Documentary', year: '2025' },
  { title: 'Pulse Cut Campaign', category: 'Commercial', year: '2024' },
  { title: 'Midnight Creator Reel', category: 'YouTube', year: '2024' },
  { title: 'Lightfall Narrative', category: 'Short Film', year: '2023' },
];

export default function Work() {
  return (
    <section className="section section-work reveal-on-scroll" id="work">
      <div className="section-inner">
        <p className="section-label">Selected Work</p>
        <h2 className="section-title">Stories Crafted Frame by Frame</h2>

        <div className="work-grid">
          {PROJECTS.map((project) => (
            <article className="work-card" key={project.title}>
              <div className="work-card-top">
                <span className="work-tag">{project.category}</span>
                <span className="work-year">{project.year}</span>
              </div>
              <h3 className="work-name">{project.title}</h3>
              <div className="work-hover" aria-hidden="true">
                <span className="work-arrow">&rarr;</span>
              </div>
            </article>
          ))}
        </div>
      </div>
    </section>
  );
}
